import { Processor, WorkerHost, OnWorkerEvent } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Job, DelayedError } from 'bullmq';
import { HotLeadService } from '../hot-lead.service';
import { ClsService } from 'nestjs-cls';
import { AiAnalysisJobData } from '../../../queue/interfaces/job-data.interface';
import { AppException } from '../../../common/exceptions/app.exception';
import { RedisService } from '../../../common/redis/redis.service';
import { ProviderDegradationException } from '../../../common/exceptions/provider-degradation.exception';

@Processor('ai-analysis', {
  concurrency: 5,
  limiter: {
    max: 10,
    duration: 1000,
  },
})
export class AiAnalysisProcessor extends WorkerHost {
  private readonly logger = new Logger(AiAnalysisProcessor.name);

  constructor(
    private readonly hotLeadService: HotLeadService,
    private readonly cls: ClsService,
    private readonly redisService: RedisService,
  ) {
    super();
  }

  async process(
    job: Job<AiAnalysisJobData, unknown, string>,
  ): Promise<unknown> {
    const { tenantId, conversationId, messageContent } = job.data;

    if (!tenantId || !conversationId || !messageContent) {
      this.logger.warn(`Invalid job data for ai-analysis: ${job.id}`);
      return;
    }

    // Queue Isolation / Noisy Neighbor prevention
    const MAX_CONCURRENT_PER_TENANT = 2;
    const activeJobsKey = `tenant:${tenantId}:aianalysis-active`;
    const activeCount = await this.redisService.incr(activeJobsKey);

    if (activeCount === 1) {
      await this.redisService.expire(activeJobsKey, 60);
    }

    if (activeCount > MAX_CONCURRENT_PER_TENANT) {
      await this.redisService.decr(activeJobsKey);
      this.logger.warn(
        `Tenant ${tenantId} exceeded AI analysis concurrency limit (${MAX_CONCURRENT_PER_TENANT}). Delaying job ${job.id}.`,
      );
      await job.moveToDelayed(Date.now() + 2000, job.token);
      throw new DelayedError();
    }

    try {
      // MEMORY REQUIREMENT: Background workers MUST explicitly wrap execution in cls.run()
      // and manually inject context variables like tenantId to maintain isolation.
      return await this.cls.run(async () => {
        this.cls.set('tenantId', tenantId);

        this.logger.log(
          `Processing AI analysis for conversation: ${conversationId}`,
        );
        try {
          let timeoutId: NodeJS.Timeout;
          const timeout = new Promise<never>((_, reject) => {
            timeoutId = setTimeout(() => {
              reject(
                new AppException('AI_TIMEOUT', 'AI analysis timed out', 504),
              );
            }, 25000);
          });

          try {
            await Promise.race([
              this.hotLeadService.analyzeLead(conversationId, messageContent),
              timeout,
            ]);
          } finally {
            clearTimeout(timeoutId!);
          }
        } catch (error) {
          if (error instanceof ProviderDegradationException) {
            this.logger.warn(
              `Provider Degradation: AI Circuit Breaker Open. Delaying ai-analysis job ${job.id}.`,
            );
            await job.moveToDelayed(Date.now() + 30000, job.token);
            throw new DelayedError();
          }

          this.logger.error(
            `Error during AI analysis for ${conversationId}: ${error instanceof Error ? error.message : 'Unknown error'}`,
          );
          throw error;
        }
      });
    } finally {
      await this.redisService.decr(activeJobsKey);
    }
  }

  @OnWorkerEvent('failed')
  async onFailed(job: Job, error: Error) {
    if (
      error.message.includes('moveToDelayed') ||
      error.message.includes('DelayedError')
    ) {
      return;
    }
    this.logger.error(
      `Job ${job.id} of type ${job.name} failed with error: ${error.message}`,
      error.stack,
    );
  }
}

import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger, Inject, OnModuleDestroy } from '@nestjs/common';
import { Job } from 'bullmq';
import { ClsService } from 'nestjs-cls';
import { HotLeadJobData } from '../../../queue/interfaces/job-data.interface';
import { PrismaService } from '../../../common/prisma/prisma.service';
import { ConfigService } from '@nestjs/config';
import { MailService } from '../../../mail/mail.service';
import { ConversationGateway } from '../../websocket/conversation.gateway';
import { WHATSAPP_PROVIDER } from '../../../whatsapp/interfaces/whatsapp-provider.interface';
import type { WhatsappProviderInterface } from '../../../whatsapp/interfaces/whatsapp-provider.interface';
import { RedisService } from '../../../common/redis/redis.service';

@Processor('hot-lead')
export class HotLeadProcessor extends WorkerHost {
  private readonly logger = new Logger(HotLeadProcessor.name);

  constructor(
    private readonly cls: ClsService,
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
    private readonly mailService: MailService,
    private readonly conversationGateway: ConversationGateway,
    @Inject(WHATSAPP_PROVIDER)
    private readonly whatsappProvider: WhatsappProviderInterface,
    private readonly redisService: RedisService,
  ) {
    super();
  }

  async process(job: Job<HotLeadJobData, unknown, string>): Promise<unknown> {
    const { tenantId, leadId, conversationId, heatTier, heatReasons } =
      job.data;

    if (!tenantId || !leadId) {
      this.logger.warn(`Invalid job data for hot-lead: ${job.id}`);
      return;
    }

    // MEMORY REQUIREMENT: Background workers MUST explicitly wrap execution in cls.run()
    // and manually inject context variables like tenantId to maintain isolation.
    return this.cls.run(async () => {
      this.cls.set('tenantId', tenantId);
      this.logger.log(`Processing hot lead alert for lead: ${leadId}`);

      const lead = await this.prisma.lead.findFirst({
        where: { id: leadId, tenantId },
      });

      if (!lead) {
        this.logger.warn(`Lead not found: ${leadId} for tenant ${tenantId}`);
        return;
      }

      // 1. Fetch Notification Preference
      const pref = await this.prisma.notificationPreference.findUnique({
        where: { tenantId },
      });

      if (pref && !pref.hotLeadAlert) {
        this.logger.log(`Hot lead alerts are disabled for tenant ${tenantId}`);
        return;
      }

      // 2. Fetch main user/sales for this tenant
      // We assume the first user (or the one who created it) is the primary contact
      const user = await this.prisma.user.findFirst({
        where: { tenantId },
        orderBy: { createdAt: 'asc' },
      });

      if (!user) {
        this.logger.warn(
          `No user found for tenant ${tenantId} to send alert to`,
        );
        return;
      }

      const leadNameOrPhone = lead.customerName || lead.customerPhone;
      const frontendUrl =
        this.configService.get<string>('FRONTEND_URL') ||
        'http://localhost:3000';
      const deepLink = `${frontendUrl}/dashboard/conversations/${conversationId}`;

      // 3. WhatsApp Internal Alert Logic
      if (user.waPersonalNumber) {
        // Audit rule: Cache keys must be namespaced with tenantId to prevent leakage
        const redisKey = `tenant:${tenantId}:hot-lead-alert:${leadId}`;
        const isRateLimited = await this.redisService.exists(redisKey);

        if (isRateLimited) {
          this.logger.log(
            `Rate limited: skipping WA hot lead alert for lead ${leadId}`,
          );
        } else {
          const waMessage = `🚨 *Peringatan Hot Lead!* 🚨\nProspek: ${leadNameOrPhone}\nKetertarikan: ${heatTier}\nAlasan: ${heatReasons.join(', ')}\nLink: ${deepLink}`;

          try {
            await this.whatsappProvider.sendMessage({
              to: user.waPersonalNumber,
              message: waMessage,
              tenantId: tenantId, // Context tracking
            });
            this.logger.log(`WhatsApp hot lead alert sent to user ${user.id}`);

            // Set rate limit: Max 1 alert per 30 minutes (1800 seconds)
            await this.redisService.set(redisKey, '1', 1800);
          } catch (error) {
            this.logger.error(
              `Failed to send WA hot lead alert to user ${user.id}: ${error instanceof Error ? error.message : 'Unknown'}`,
            );
          }
        }
      } else {
        this.logger.warn(
          `Cannot send WA alert. User phone missing for user ${user.id}`,
        );
      }

      // 4. Implementasi Email Alert Logic (Conditional)
      if (heatTier === 'CRITICAL' && user.email) {
        await this.mailService.sendHotLeadAlert(user.email, {
          leadName: leadNameOrPhone,
          tier: heatTier,
          reasons: heatReasons,
          link: deepLink,
        });
      }

      // 5. WebSocket Update
      this.conversationGateway.broadcastLeadHeatChanged(tenantId, {
        conversationId,
        heatTier,
        heatReasons,
      });

      return true;
    });
  }
}

